function pickWidth() {
  try {
    const w = new URL(import.meta.url).searchParams.get("w");
    if (w && SETS[w]) return w;
  } catch (e) { /* not loaded as a module: fall back to default */ }
  return DEFAULT_WIDTH;
}
const WIDTH = pickWidth();
const ICONS = SETS[WIDTH] || SETS[DEFAULT_WIDTH];

async function getIcon(name) {
  const d = ICONS[name];
  if (!d) {
    console.warn(`iconoir-icons: unknown icon "${name}"`);
    return {};
  }
  return { path: d, viewBox: VIEWBOX };
}

async function getIconList() {
  return Object.keys(ICONS).map((name) => ({ name }));
}

